+const fn tool_names() -> [&'static str; 7] {
+    ["read", "write", "edit", "bash", "grep", "find", "ls"]
+}
+
+fn assistant_text(message: &AssistantMessage) -> String {
+    message
+        .content
+        .iter()
+        .filter_map(|block| match block {
+            ContentBlock::Text(text) => Some(text.text.as_str()),
+            _ => None,
+        })
+        .collect::<String>()
+}
+
+fn make_assistant(
+    provider_name: &str,
+    stop_reason: StopReason,
+    content: Vec<ContentBlock>,
+    total_tokens: u64,
+) -> AssistantMessage {
+    AssistantMessage {
+        content,
+        api: "test-api".to_string(),
+        provider: provider_name.to_string(),
+        model: "test-model".to_string(),
+        usage: Usage {
+            total_tokens,
+            output: total_tokens,
+            ..Usage::default()
+        },
+        stop_reason,
+        error_message: None,
+        timestamp: 0,
+    }
+}
+
+fn stream_done(
+    msg: AssistantMessage,
+) -> Pin<Box<dyn Stream<Item = Result<StreamEvent>> + Send>> {
+    let partial = AssistantMessage {
+        content: Vec::new(),
+        api: msg.api.clone(),
+        provider: msg.provider.clone(),
+        model: msg.model.clone(),
+        usage: Usage::default(),
+        stop_reason: StopReason::Stop,
+        error_message: None,
+        timestamp: 0,
+    };
+    Box::pin(futures::stream::iter(vec![
+        Ok(StreamEvent::Start { partial }),
+        Ok(StreamEvent::Done {
+            reason: msg.stop_reason,
+            message: msg,
+        }),
+    ]))
+}
+
+fn make_agent_session(
+    cwd: &Path,
+    provider: Arc<dyn Provider>,
+    session: Arc<asupersync::sync::Mutex<Session>>,
+    max_tool_iterations: usize,
+) -> AgentSession {
+    let agent = Agent::new(
+        provider,
+        ToolRegistry::new(&tool_names(), cwd, None),
+        AgentConfig {
+            max_tool_iterations,
+            stream_options: StreamOptions {
+                api_key: Some("test-key".to_string()),
+                ..StreamOptions::default()
+            },
+            ..AgentConfig::default()
+        },
+    );
+    AgentSession::new(agent, session, true, ResolvedCompactionSettings::default())
+}
