+    let mut entry = make_entry("google", "fail-test", &base_url);
+    entry.api_key = Some("test-key".to_string());
+    entry.model.api.clear();
+    let provider = create_provider(&entry, None).expect("create gemini provider");
+    (provider, server)
+}
