+    let cwd = harness.temp_dir().to_path_buf();
+    let metrics_store = Arc::new(Mutex::new(Vec::<TurnMetrics>::new()));
+    let timeline_store = Arc::new(Mutex::new(Vec::<serde_json::Value>::new()));
+    let ms = Arc::clone(&metrics_store);
