+            window[0].turn_index,
+            window[1].turn_index,
+        );
+    }
+
+    // Assertion: final cumulative tokens = sum of individual tokens
+    let total: u64 = metrics.iter().map(|m| m.tokens).sum();
+    let final_cumulative = metrics.last().map_or(0, |m| m.cumulative_tokens);
